# Post-auth assertion block (added after session.refresh())
def assert_authenticated(driver, selector="[data-test-id='nav-profile-menu']"):
    try:
        el = driver.find_element(By.CSS_SELECTOR, selector)
        return {"performed": True, "passed": bool(el), "selector_checked": selector, "failure_reason": None}
    except NoSuchElementException:
        return {"performed": True, "passed": False, "selector_checked": selector,
                "failure_reason": "auth_selector_not_found — likely unauthenticated redirect"}
```

